```bash
sed -i '/if (HasMustTailCalls) {/a\    for (const BasicBlock &BB : F) {
      if (const auto *TC = BB.getTerminatingMustTailCall()) {
        if (!isa<ReturnInst>(TC->getNextNode()) && !isa<BitCastInst>(TC->getNextNode())) {
          LLVM_DEBUG(dbgs() << "Invalid musttail call placement detected during deadargelim\n");
          markLive(F);
          return;
        }
      }
    }' ./llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp
```

